<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Kanban Board</title>
<style>
  body {
    font-family: Arial, sans-serif;
    background:#f0f2f5;
    margin:0;
    padding:20px;
    box-sizing:border-box;
  }
  .controls {
    margin-bottom:20px;
    display:flex;
    gap:10px;
  }
  #new-card {
    flex:1;
    padding:8px;
    font-size:14px;
  }
  #add-card {
    padding:8px 16px;
    font-size:14px;
    cursor:pointer;
  }
  .board {
    display:flex;
    gap:15px;
    justify-content:space-between;
  }
  .column {
    background:#e2e4e6;
    border-radius:6px;
    flex:1;
    display:flex;
    flex-direction:column;
    max-height:80vh;
  }
  .col-header {
    padding:10px;
    font-weight:bold;
    background:#d6dadc;
    border-top-left-radius:6px;
    border-top-right-radius:6px;
    display:flex;
    justify-content:space-between;
    align-items:center;
  }
  .col-header .count {
    background:#fff;
    border-radius:12px;
    padding:2px 8px;
    font-size:12px;
  }
  .card-container {
    flex:1;
    overflow-y:auto;
    padding:10px;
  }
  .card {
    background:#fff;
    border-radius:4px;
    padding:8px 10px;
    margin-bottom:10px;
    box-shadow:0 1px 2px rgba(0,0,0,0.1);
    display:flex;
    justify-content:space-between;
    align-items:center;
    cursor:grab;
  }
  .card:active {
    cursor:grabbing;
  }
  .card-del {
    background:#ff4d4f;
    border:none;
    color:#fff;
    border-radius:3px;
    padding:2px 6px;
    cursor:pointer;
    font-size:12px;
  }
</style>
</head>
<body>

<div class="controls">
  <input type="text" id="new-card" placeholder="New card title">
  <button id="add-card">Add Card</button>
</div>

<div class="board">
  <div class="column" id="col-todo">
    <div class="col-header">To Do <span class="count">0</span></div>
    <div class="card-container"></div>
  </div>
  <div class="column" id="col-doing">
    <div class="col-header">Doing <span class="count">0</span></div>
    <div class="card-container"></div>
  </div>
  <div class="column" id="col-done">
    <div class="col-header">Done <span class="count">0</span></div>
    <div class="card-container"></div>
  </div>
</div>

<script>
(() => {
  const STORAGE_KEY = 'kanbanBoard';
  let board = []; // array of {id, title, column}

  const cols = {
    todo: document.querySelector('#col-todo .card-container'),
    doing: document.querySelector('#col-doing .card-container'),
    done: document.querySelector('#col-done .card-container')
  };

  const countSpans = {
    todo: document.querySelector('#col-todo .count'),
    doing: document.querySelector('#col-doing .count'),
    done: document.querySelector('#col-done .count')
  };

  // Load from localStorage
  function loadBoard() {
    const data = localStorage.getItem(STORAGE_KEY);
    if (data) {
      try {
        board = JSON.parse(data);
      } catch (e) {
        board = [];
      }
    }
  }

  // Save to localStorage
  function saveBoard() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(board));
  }

  // Create a card DOM element
  function createCardElement(card) {
    const el = document.createElement('div');
    el.className = 'card';
    el.draggable = true;
    el.dataset.id = card.id;

    const title = document.createElement('span');
    title.textContent = card.title;

    const delBtn = document.createElement('button');
    delBtn.className = 'card-del';
    delBtn.textContent = '✕';
    delBtn.addEventListener('click', () => {
      deleteCard(card.id);
    });

    el.appendChild(title);
    el.appendChild(delBtn);

    // Drag events
    el.addEventListener('dragstart', e => {
      e.dataTransfer.setData('text/plain', card.id);
      // optional visual cue
      setTimeout(() => el.classList.add('dragging'), 0);
    });
    el.addEventListener('dragend', () => {
      el.classList.remove('dragging');
    });

    return el;
  }

  // Render all cards
  function renderBoard() {
    // Clear containers
    Object.values(cols).forEach(c => c.innerHTML = '');
    board.forEach(card => {
      const colKey = card.column;
      const container = cols[colKey];
      if (container) {
        container.appendChild(createCardElement(card));
      }
    });
    updateCounts();
  }

  // Update counts in headers
  function updateCounts() {
    const counts = {todo:0, doing:0, done:0};
    board.forEach(card => {
      if (counts[card.column] !== undefined) counts[card.column]++;
    });
    countSpans.todo.textContent = counts.todo;
    countSpans.doing.textContent = counts.doing;
    countSpans.done.textContent = counts.done;
  }

  // Add a new card
  function addCard(title) {
    const id = Date.now().toString() + Math.random().toString(36).substr(2,5);
    const card = {id, title, column:'todo'};
    board.push(card);
    saveBoard();
    renderBoard();
  }

  // Delete a card
  function deleteCard(id) {
    board = board.filter(c => c.id !== id);
    saveBoard();
    renderBoard();
  }

  // Move card to a column
  function moveCard(id, newColumn) {
    const card = board.find(c => c.id === id);
    if (card && card.column !== newColumn) {
      card.column = newColumn;
      saveBoard();
      renderBoard();
    }
  }

  // Setup dragover & drop on columns
  function setupColumnDropping(colKey) {
    const columnDiv = document.getElementById(`col-${colKey}`);
    columnDiv.addEventListener('dragover', e => {
      e.preventDefault(); // allow drop
    });
    columnDiv.addEventListener('drop', e => {
      e.preventDefault();
      const id = e.dataTransfer.getData('text/plain');
      moveCard(id, colKey);
    });
  }

  // Initialize
  function init() {
    loadBoard();
    renderBoard();

    // Add card button
    document.getElementById('add-card').addEventListener('click', () => {
      const input = document.getElementById('new-card');
      const text = input.value.trim();
      if (text) {
        addCard(text);
        input.value = '';
      }
    });

    // Enter key on input
    document.getElementById('new-card').addEventListener('keypress', e => {
      if (e.key === 'Enter') {
        e.preventDefault();
        document.getElementById('add-card').click();
      }
    });

    // Setup drop zones
    ['todo','doing','done'].forEach(setupColumnDropping);
  }

  document.addEventListener('DOMContentLoaded', init);
})();
</script>

</body>
</html>
